# Generate Cyclic Cayley Graph

def cyclic_cayley(n, H):
    """ Creates adjacency matrix for Cayley graph for cyclic group C_n generated by H. C_n is additive i.e. elements are 0,...,n-1.
    
    Args:
        n: number of nodes
        H: subset of C_n that generates edges for the Cayley graph
    
    Returns:
        adj_matrix: adjacency matrix of the Cayley graph
    
    """
    adj_matrix = np.zeros((n,n))
    for i in range(n):
        for h in H:
            j = (i+h)%n
            adj_matrix[i,j] = 1
    return adj_matrix


