# Compute orbits of a cyclic Cayley graph

def get_orbits(n, s):
    """ Partitions all possible starting sets into their equivalent orbits
    
    Args:
        n: number of nodes in cyclic Cayley graph
        s: cardinality of starting sets
    
    Returns:
        orbits: list whose elements are lists of starting sets which lie in the same orbit
    
    """
    orbits = []
    for state in list(combinations(range(n), s)):
        if len(orbits) == 0:
            new_orbit = [set(state)]
#            fix a j in Cn to add by
            for j in range(1, n):
#                add each node in initial starting set by j
                new_state = []
                for i in state:
                    k = (i+j)%n
                    new_state.append(k)
                if not set(new_state) in new_orbit:
                    new_orbit.append(set(new_state))
            orbits.append(new_orbit)
        else:
#            if the current state is already in another orbit, move to the next possible starting state    
            for orbit in orbits:
                if set(state) in orbit:
                    break
#            if the starting state was not in any previous orbits, generate that state's orbit and append to the list of orbits
            else:
                new_orbit = [set(state)]
#                fix a j in Cn to add by
                for j in range(1,n):
#                    add each state by j
                    new_state = []
                    for i in state:
                        k = (i+j)%n
                        new_state.append(k)
                    if not set(new_state) in new_orbit:
                        new_orbit.append(set(new_state))
                orbits.append(new_orbit)
    return orbits

